                                  CREATE view [SSRS].[League_SeasonCurrLast]     as    Select * FROM   (  SELECT League_ID        ,REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' ') AS Name         ,[year_of_Fixture]        ,[MonthofFixture]        ,[No Result]        ,[Abandoned]        ,[Cancelled]        ,[Conceded]        ,[InProgress]        ,[Win]        ,[ShortSided]    FROM [SSRS].[Leagues_SeasonTD_2026]    UNION      Select League_ID         ,REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' ') AS Name         ,[year_of_Fixture]        ,[MonthofFixture]        ,[No Result]        ,[Abandoned]        ,[Cancelled]        ,[Conceded]        ,[InProgress]        ,[Win]        ,[ShortSided]   FROM    [SSRS].Leagues_2025Season     )A     WHere MonthofFixture =  DATEPART(month,getdate())-1   --and League_ID = 15363                